#'
#' @author Kaifeng Lu, \email{kaifenglu@@gmail.com}
#'
#' @examples
#'
#' float_to_fraction(5/3)
#'
#' @export
float_to_fraction <- function(x, tol = 0.000001) {
    .Call(`_lrstat_float_to_fraction`, x, tol)
}

